class Solution:
    def maxTotalValue(self, nums, k):
        n = len(nums)
        allvals = []
        for l in range(n):
            mn = mx = nums[l]
            for r in range(l, n):
                v = nums[r]
                if v < mn:
                    mn = v
                if v > mx:
                    mx = v
                allvals.append(mx - mn)
        maxv = max(allvals)
        def cnt_sum(X):
            c = 0
            s = 0
            for v in allvals:
                if v >= X:
                    c += 1
                    s += v
            return c, s
        lo, hi = 0, maxv
        bestX = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            c, _ = cnt_sum(mid)
            if c >= k:
                bestX = mid
                lo = mid + 1
            else:
                hi = mid - 1
        c, s = cnt_sum(bestX)
        return s - (c - k) * bestX

