import heapq
class Solution:
    def maxTotalValue(self, nums, k):
        n = len(nums)
        vals = []
        for l in range(n):
            mn = mx = nums[l]
            for r in range(l, n):
                v = nums[r]
                if v < mn:
                    mn = v
                if v > mx:
                    mx = v
                vals.append(mx - mn)
        return sum(heapq.nlargest(k, vals))

