var maxTotalValue = function(nums, k) {
    const n = nums.length;
    const vals = [];
    for (let l = 0; l < n; l++) {
        let mn = nums[l], mx = nums[l];
        for (let r = l; r < n; r++) {
            const v = nums[r];
            if (v < mn) mn = v;
            if (v > mx) mx = v;
            vals.push(mx - mn);
        }
    }
    vals.sort((a, b) => b - a);
    let total = 0;
    const lim = Math.min(k, vals.length);
    for (let i = 0; i < lim; i++) total += vals[i];
    return total;
};
